4495       ConstOps.push_back(ConstOp);
4496     else
4497       return nullptr;
4498   }
4499 
4500   // Consider:
4501   //   %cmp = icmp eq i32 %x, 2147483647
4502   //   %add = add nsw i32 %x, 1
4503   //   %sel = select i1 %cmp, i32 -2147483648, i32 %add
4504   //
4505   // We can't replace %sel with %add unless we strip away the flags (which
4506   // will be done in InstCombine).
